import{_ as o,o as a,c as r,ak as s}from"./chunks/framework.0gCUzwrR.js";const m=JSON.parse('{"title":"10. Puertos","description":"","frontmatter":{"title":"10. Puertos","parent":"Linux","nav_exclude":true},"headers":[],"relativePath":"linux/linux/puertos.md","filePath":"linux/linux/puertos.md","lastUpdated":1775402759000}'),n={name:"linux/linux/puertos.md"};function i(t,e,c,d,l,p){return a(),r("div",null,[...e[0]||(e[0]=[s(`<h2 id="_1-introduccion-puertos-de-red" tabindex="-1">1. Introducción. Puertos de red <a class="header-anchor" href="#_1-introduccion-puertos-de-red" aria-label="Permalink to “1. Introducción. Puertos de red”">​</a></h2><p>En la gestión de redes y operaciones de servidores, comprender con precisión el estado de los puertos es esencial. Especialmente al usar Ubuntu, verificar qué puertos están abiertos y qué procesos los están utilizando ayuda a reforzar la seguridad y permite una solución de problemas más rápida.</p><p>Este artículo explica los comandos y herramientas básicos para comprobar puertos en Ubuntu. Proporciona pasos prácticos y fáciles de entender para usuarios principiantes e intermedios, así que asegúrate de leer hasta el final.</p><h2 id="_2-¿que-es-un-puerto" tabindex="-1">2. ¿Qué es un puerto? <a class="header-anchor" href="#_2-¿que-es-un-puerto" aria-label="Permalink to “2. ¿Qué es un puerto?”">​</a></h2><h3 id="_2-1-concepto-basico-de-los-puertos" tabindex="-1">2.1 Concepto básico de los puertos <a class="header-anchor" href="#_2-1-concepto-basico-de-los-puertos" aria-label="Permalink to “2.1 Concepto básico de los puertos”">​</a></h3><p>Un puerto es un punto final de comunicación virtual que las computadoras y dispositivos de red utilizan para enviar y recibir datos. Específicamente, cuando varias aplicaciones se comunican simultáneamente en la misma dirección IP, los puertos identifican y enrutan los datos hacia la aplicación correcta.</p><p>Por ejemplo, un servidor web usa el puerto 80 para tráfico HTTP. Si el mismo servidor permite acceso SSH, utiliza el puerto 22. Dado que los servicios se distinguen por números de puerto, comprobar el estado de los puertos es crucial en la gestión de redes.</p><h3 id="_2-2-tipos-y-funciones-de-los-puertos" tabindex="-1">2.2 Tipos y funciones de los puertos <a class="header-anchor" href="#_2-2-tipos-y-funciones-de-los-puertos" aria-label="Permalink to “2.2 Tipos y funciones de los puertos”">​</a></h3><p>Los puertos se clasifican en tres grupos principales:</p><p>1️⃣ <strong>Puertos bien conocidos (0–1023)</strong></p><ul><li>Números de puerto estandarizados globalmente asignados a servicios de uso frecuente.</li><li>Ejemplos: <ul><li>HTTP: 80</li><li>HTTPS: 443</li><li>SSH: 22</li></ul></li></ul><p>2️⃣ <strong>Puertos registrados (1024–49151)</strong></p><ul><li><p>Puertos utilizados por aplicaciones o empresas específicas. wp:list /wp:list</p></li><li><p>Ejemplos:</p><ul><li>MySQL: 3306</li><li>PostgreSQL: 5432</li></ul></li></ul><p>3️⃣ <strong>Puertos dinámicos (49152–65535)</strong></p><ul><li>Puertos usados temporalmente por aplicaciones, comúnmente en comunicaciones del lado del cliente.</li></ul><p>Comprender esta clasificación facilita determinar para qué se utiliza cada número de puerto.</p><h2 id="_3-como-comprobar-puertos-en-ubuntu" tabindex="-1">3. Cómo comprobar puertos en Ubuntu <a class="header-anchor" href="#_3-como-comprobar-puertos-en-ubuntu" aria-label="Permalink to “3. Cómo comprobar puertos en Ubuntu”">​</a></h2><p>Ubuntu ofrece varias herramientas para verificar el estado de los puertos. Esta sección explica cuatro comandos particularmente útiles.</p><h3 id="_3-1-uso-del-comando-ss" tabindex="-1">3.1 Uso del comando ss <a class="header-anchor" href="#_3-1-uso-del-comando-ss" aria-label="Permalink to “3.1 Uso del comando ss”">​</a></h3><p>El comando <code>ss</code> es una herramienta potente de gestión de redes para sistemas Linux. Se ejecuta rápidamente y proporciona información detallada de las conexiones.</p><p><strong>Comando básico:</strong></p><pre><code>sudo ss -ltn
</code></pre><p><strong>Detalles de las opciones:</strong></p><ul><li><strong>-l</strong> : Muestra solo los puertos en estado <code>LISTEN</code>.</li><li><strong>-t</strong> : Muestra solo el protocolo <code>TCP</code>.</li><li><strong>-n</strong> : Muestra direcciones y números de puerto en forma numérica.</li></ul><p><strong>Salida de ejemplo:</strong></p><pre><code>State       Recv-Q Send-Q      Local Address:Port        Peer Address:Port  
LISTEN      0      128              0.0.0.0:22               0.0.0.0:*
</code></pre><h3 id="_3-2-uso-del-comando-netstat" tabindex="-1">3.2 Uso del comando netstat <a class="header-anchor" href="#_3-2-uso-del-comando-netstat" aria-label="Permalink to “3.2 Uso del comando netstat”">​</a></h3><p>El comando <code>netstat</code> ha sido ampliamente utilizado como herramienta de gestión de redes durante muchos años. Aunque está siendo reemplazado gradualmente por <code>ss</code>, sigue estando disponible en muchos sistemas.</p><p><strong>Comando básico:</strong></p><pre><code>sudo netstat -ltn
</code></pre><p><strong>Salida de ejemplo:</strong></p><pre><code>Proto Recv-Q Send-Q Local Address           Foreign Address         State      
tcp        0      0 0.0.0.0:22              0.0.0.0:*               LISTEN
</code></pre><h3 id="_3-3-uso-del-comando-lsof" tabindex="-1">3.3 Uso del comando lsof <a class="header-anchor" href="#_3-3-uso-del-comando-lsof" aria-label="Permalink to “3.3 Uso del comando lsof”">​</a></h3><p><code>lsof</code> es útil para identificar los procesos que están usando puertos específicos.</p><p><strong>Comprobar un puerto concreto:</strong></p><pre><code>sudo lsof -i :80
</code></pre><p><strong>Salida de ejemplo:</strong></p><pre><code>COMMAND   PID   USER   FD   TYPE DEVICE SIZE/OFF NODE NAME
apache2   1234  www    4u   IPv4  12345 0t0      TCP *:http (LISTEN)
</code></pre><h3 id="_3-4-uso-del-comando-nmap" tabindex="-1">3.4 Uso del comando nmap <a class="header-anchor" href="#_3-4-uso-del-comando-nmap" aria-label="Permalink to “3.4 Uso del comando nmap”">​</a></h3><p><code>nmap</code> es una herramienta de escaneo de redes que se usa frecuentemente para diagnósticos de seguridad.</p><p><strong>Escanear localhost:</strong></p><pre><code>sudo nmap localhost
</code></pre><p><strong>Salida de ejemplo:</strong></p><pre><code>Starting Nmap 7.80 ( https://nmap.org ) at 2024-12-21 18:00 JST
Nmap scan report for localhost (127.0.0.1)
Host is up (0.00013s latency).
PORT    STATE SERVICE
22/tcp  open  ssh
80/tcp  open  http
</code></pre><p><strong>Puntos clave:</strong></p><ul><li>Se listan los puertos abiertos y los servicios asociados.</li><li>Es posible escanear servidores externos, pero se requiere la autorización adecuada.</li></ul><h2 id="_4-comprobacion-de-la-configuracion-del-firewall" tabindex="-1">4. Comprobación de la configuración del firewall <a class="header-anchor" href="#_4-comprobacion-de-la-configuracion-del-firewall" aria-label="Permalink to “4. Comprobación de la configuración del firewall”">​</a></h2><p>En Ubuntu, los firewalls se utilizan comúnmente para mejorar la seguridad. <code>ufw</code> (Uncomplicated Firewall), en particular, es una herramienta de gestión simple pero potente ampliamente utilizada para este propósito. Esta sección explica cómo verificar el estado de los puertos y modificar configuraciones usando <code>ufw</code>.</p><h3 id="_4-1-verificar-el-estado-de-ufw" tabindex="-1">4.1 Verificar el estado de ufw <a class="header-anchor" href="#_4-1-verificar-el-estado-de-ufw" aria-label="Permalink to “4.1 Verificar el estado de ufw”">​</a></h3><p><strong>Comando para verificar el estado del firewall:</strong></p><pre><code>sudo ufw status verbose
</code></pre><p><strong>Salida de ejemplo:</strong></p><pre><code>Status: active
Logging: on (low)
Default: deny (incoming), allow (outgoing)
New profiles: skip
To                         Action      From
--                         ------      ----
22/tcp                     ALLOW       Anywhere
80/tcp                     ALLOW       Anywhere
</code></pre><p><strong>Explicación:</strong></p><ul><li><strong>Status: active</strong> — indica que el firewall está habilitado.</li><li><strong>Logging: on</strong> — el registro está habilitado y la actividad del firewall se está grabando.</li><li><strong>Default: deny (incoming), allow (outgoing)</strong> — las conexiones entrantes se deniegan por defecto, mientras que las conexiones salientes se permiten.</li><li><strong>ALLOW</strong> — muestra puertos o servicios que están explícitamente permitidos (por ejemplo, SSH y HTTP).</li></ul><p><strong>Consejo:</strong><br> Si el firewall está deshabilitado (<code>Status: inactive</code>), habilítelo con el siguiente comando:</p><pre><code>sudo ufw enable
</code></pre><h3 id="_4-2-permitir-o-bloquear-puertos" tabindex="-1">4.2 Permitir o bloquear puertos <a class="header-anchor" href="#_4-2-permitir-o-bloquear-puertos" aria-label="Permalink to “4.2 Permitir o bloquear puertos”">​</a></h3><p><strong>Comando para permitir un puerto:</strong></p><pre><code>sudo ufw allow 22/tcp
</code></pre><p><strong>Explicación:</strong></p><ul><li>Permite conexiones TCP en el puerto 22 (SSH).</li></ul><p><strong>Comando para bloquear un puerto:</strong></p><pre><code>sudo ufw deny 80/tcp
</code></pre><p><strong>Explicación:</strong></p><ul><li><p>Bloquea el acceso al puerto 80 (HTTP). <strong>Ejemplo: Permitir acceso desde una dirección IP específica únicamente</strong></p><p>sudo ufw allow from 192.168.1.100 to any port 22 proto tcp</p></li></ul><p><strong>Explicación:</strong></p><ul><li>Permite conexiones SSH desde la dirección IP <code>192.168.1.100</code> únicamente.</li></ul><h3 id="_4-3-restablecer-y-revisar-configuraciones" tabindex="-1">4.3 Restablecer y revisar configuraciones <a class="header-anchor" href="#_4-3-restablecer-y-revisar-configuraciones" aria-label="Permalink to “4.3 Restablecer y revisar configuraciones”">​</a></h3><p>Para restablecer la configuración del firewall y comenzar de nuevo, ejecute el siguiente comando:</p><pre><code>sudo ufw reset
</code></pre><p>Esto elimina todas las reglas y devuelve el firewall a su estado predeterminado. Si restablece las configuraciones, asegúrese de revisar y volver a aplicar las reglas necesarias.</p><h2 id="_5-ejemplo-practico-verificar-el-estado-de-un-puerto-especifico" tabindex="-1">5. Ejemplo práctico: Verificar el estado de un puerto específico <a class="header-anchor" href="#_5-ejemplo-practico-verificar-el-estado-de-un-puerto-especifico" aria-label="Permalink to “5. Ejemplo práctico: Verificar el estado de un puerto específico”">​</a></h2><p>Esta sección proporciona un ejemplo práctico usando SSH (puerto 22) para mostrar cómo verificar el estado del puerto.</p><h3 id="_5-1-verificar-el-estado-del-puerto" tabindex="-1">5.1 Verificar el estado del puerto <a class="header-anchor" href="#_5-1-verificar-el-estado-del-puerto" aria-label="Permalink to “5.1 Verificar el estado del puerto”">​</a></h3><p><strong>Comando de ejemplo:</strong></p><pre><code>sudo ss -ltn | grep 22
</code></pre><p><strong>Salida de ejemplo:</strong></p><pre><code>LISTEN      0      128        0.0.0.0:22            0.0.0.0:*
</code></pre><p><strong>Puntos clave:</strong></p><ul><li>Si aparece <code>LISTEN</code> en la salida, el puerto está abierto y esperando conexiones.</li><li><code>0.0.0.0</code> indica que se aceptan conexiones desde todas las direcciones IP.</li></ul><h3 id="_5-2-verificar-el-proceso-en-ejecucion" tabindex="-1">5.2 Verificar el proceso en ejecución <a class="header-anchor" href="#_5-2-verificar-el-proceso-en-ejecucion" aria-label="Permalink to “5.2 Verificar el proceso en ejecución”">​</a></h3><p><strong>Comando de ejemplo:</strong></p><pre><code>sudo lsof -i :22
</code></pre><p><strong>Salida de ejemplo:</strong></p><pre><code>COMMAND   PID   USER   FD   TYPE DEVICE SIZE/OFF NODE NAME
sshd      1234  root   3u   IPv4  56789 0t0      TCP *:ssh (LISTEN)
</code></pre><p><strong>Puntos clave:</strong></p><ul><li><code>sshd</code> es el proceso daemon que gestiona las conexiones SSH.</li><li>Puede detener o reiniciar el proceso usando su ID de proceso (PID).</li></ul><p><strong>Ejemplo de detención de un proceso:</strong></p><pre><code>sudo kill 1234
</code></pre><h3 id="_5-3-ejemplo-de-resolucion-de-problemas" tabindex="-1">5.3 Ejemplo de resolución de problemas <a class="header-anchor" href="#_5-3-ejemplo-de-resolucion-de-problemas" aria-label="Permalink to “5.3 Ejemplo de resolución de problemas”">​</a></h3><p><strong>Problema:</strong> Qué hacer cuando un puerto está cerrado o inaccesible.</p><p><strong>Pasos:</strong></p><ol><li><p>Verificar las configuraciones del firewall.</p><pre><code> sudo ufw status verbose
</code></pre></li><li><p>Si el puerto está bloqueado, permítalo.</p><pre><code> sudo ufw allow 22/tcp
</code></pre></li><li><p>Verificar el estado del servicio y reiniciarlo si es necesario.</p><pre><code> sudo systemctl restart ssh
</code></pre></li></ol><h2 id="_6-gestion-de-puertos-y-seguridad" tabindex="-1">6. Gestión de puertos y seguridad <a class="header-anchor" href="#_6-gestion-de-puertos-y-seguridad" aria-label="Permalink to “6. Gestión de puertos y seguridad”">​</a></h2><p>La gestión de puertos está directamente relacionada con la seguridad de la red. Esta sección explica puntos clave sobre la apertura y cierre de puertos y el mantenimiento de configuraciones seguras.</p><h3 id="_6-1-cerrar-puertos-no-utilizados" tabindex="-1">6.1 Cerrar puertos no utilizados <a class="header-anchor" href="#_6-1-cerrar-puertos-no-utilizados" aria-label="Permalink to “6.1 Cerrar puertos no utilizados”">​</a></h3><p>Los puertos que no se utilizan deben cerrarse para reducir el riesgo de acceso no autorizado.</p><p><strong>Ejemplo: Cerrar el puerto 80</strong></p><pre><code>sudo ufw deny 80/tcp
</code></pre><h3 id="_6-2-contramedidas-contra-el-escaneo-de-puertos" tabindex="-1">6.2 Contramedidas contra el escaneo de puertos <a class="header-anchor" href="#_6-2-contramedidas-contra-el-escaneo-de-puertos" aria-label="Permalink to “6.2 Contramedidas contra el escaneo de puertos”">​</a></h3><p>El escaneo de puertos es una técnica que los atacantes utilizan para identificar vulnerabilidades en un sistema. Los siguientes métodos ayudan a proteger su servidor:</p><ol><li><p><strong>Fortalecer las reglas del firewall:</strong></p><pre><code> sudo ufw default deny incoming
</code></pre></li><li><p><strong>Monitorear registros:</strong></p><pre><code> sudo tail -f /var/log/ufw.log
</code></pre></li><li><p><strong>Instalar herramientas de detección de escaneo de puertos:</strong> Use herramientas como <code>fail2ban</code> para bloquear automáticamente los intentos de acceso no autorizados.</p></li></ol><h2 id="_7-resumen" tabindex="-1">7. Resumen <a class="header-anchor" href="#_7-resumen" aria-label="Permalink to “7. Resumen”">​</a></h2><p>Este artículo explicó métodos y comandos específicos para comprobar puertos en Ubuntu. También cubrió la gestión del firewall usando <code>ufw</code> y medidas de seguridad prácticas.</p><h3 id="_7-1-puntos-clave" tabindex="-1">7.1 Puntos clave <a class="header-anchor" href="#_7-1-puntos-clave" aria-label="Permalink to “7.1 Puntos clave”">​</a></h3><ul><li><strong>Conceptos básicos y categorías de puertos:</strong> Los puertos sirven como puntos de entrada de comunicación y se clasifican en puertos bien conocidos, registrados y dinámicos.</li><li><strong>Cómo comprobar puertos:</strong> Comandos como <code>ss</code>, <code>netstat</code>, <code>lsof</code> y <code>nmap</code> proporcionan información sobre el estado de puertos y procesos.</li><li><strong>Gestión del firewall:</strong> Usando <code>ufw</code>, puedes permitir o bloquear puertos para mejorar la seguridad del sistema.</li><li><strong>Importancia de la seguridad:</strong> Cerrar puertos no utilizados, monitorear registros y usar herramientas de seguridad ayuda a mantener un entorno de red seguro.</li></ul><h3 id="_7-2-aplicacion-practica" tabindex="-1">7.2 Aplicación práctica <a class="header-anchor" href="#_7-2-aplicacion-practica" aria-label="Permalink to “7.2 Aplicación práctica”">​</a></h3><p>La gestión de puertos es un aspecto fundamental de la seguridad de red. Aplica los conocimientos adquiridos en este artículo para mantener un entorno de servidor seguro y estable.</p><h2 id="preguntas-frecuentes-preguntas-frecuentes-sobre-la-comprobacion-de-puertos-en-ubuntu" tabindex="-1">Preguntas frecuentes: Preguntas frecuentes sobre la comprobación de puertos en Ubuntu <a class="header-anchor" href="#preguntas-frecuentes-preguntas-frecuentes-sobre-la-comprobacion-de-puertos-en-ubuntu" aria-label="Permalink to “Preguntas frecuentes: Preguntas frecuentes sobre la comprobación de puertos en Ubuntu”">​</a></h2><h3 id="p1-¿que-debo-hacer-si-un-puerto-no-esta-abierto-en-ubuntu" tabindex="-1">P1. ¿Qué debo hacer si un puerto no está abierto en Ubuntu? <a class="header-anchor" href="#p1-¿que-debo-hacer-si-un-puerto-no-esta-abierto-en-ubuntu" aria-label="Permalink to “P1. ¿Qué debo hacer si un puerto no está abierto en Ubuntu?”">​</a></h3><p><strong>R:</strong><br> Intenta los siguientes pasos:</p><ol><li><p><strong>Revisar la configuración del firewall:</strong></p><pre><code>sudo ufw status verbose
</code></pre></li></ol><p>Si el puerto está bloqueado, permítelo con:</p><pre><code>sudo ufw allow [portnumber]/tcp
</code></pre><ol start="2"><li><p><strong>Verificar que el servicio esté en ejecución:</strong></p><pre><code>sudo systemctl status [servicename]
</code></pre></li></ol><p>Ejemplo para SSH:<br><code>sudo systemctl status ssh</code></p><p>Reinicia si es necesario:</p><pre><code>sudo systemctl restart [servicename]
</code></pre><ol start="3"><li><strong>Confirmar que el puerto correcto esté configurado:</strong> Revisa el archivo de configuración del servicio, como <code>/etc/ssh/sshd_config</code> para SSH, para verificar el número de puerto apropiado.</li></ol><h3 id="p2-¿cual-es-la-diferencia-entre-ss-y-netstat" tabindex="-1">P2. ¿Cuál es la diferencia entre <code>ss</code> y <code>netstat</code>? <a class="header-anchor" href="#p2-¿cual-es-la-diferencia-entre-ss-y-netstat" aria-label="Permalink to “P2. ¿Cuál es la diferencia entre ss y netstat?”">​</a></h3><p><strong>R:</strong><br> Ambas herramientas se usan para comprobar conexiones de red, pero difieren de la siguiente manera:</p><ul><li><strong><code>ss</code>:</strong> La herramienta recomendada para sistemas Linux modernos. Es más rápida y brinda información más detallada. Ejemplo: <code>sudo ss -ltn</code></li><li><strong><code>netstat</code>:</strong> Una herramienta más antigua, que se está volviendo gradualmente obsoleta, pero aún está ampliamente disponible en sistemas heredados. Ejemplo: <code>sudo netstat -ltn</code></li></ul><p>Para sistemas más recientes, se recomienda <code>ss</code>.</p><h3 id="p3-¿como-puedo-detectar-escaneos-de-puertos" tabindex="-1">P3. ¿Cómo puedo detectar escaneos de puertos? <a class="header-anchor" href="#p3-¿como-puedo-detectar-escaneos-de-puertos" aria-label="Permalink to “P3. ¿Cómo puedo detectar escaneos de puertos?”">​</a></h3><p><strong>R:</strong><br> Utiliza los siguientes métodos:</p><ol><li><p><strong>Revisar los registros del firewall:</strong></p><pre><code>sudo tail -f /var/log/ufw.log
</code></pre></li></ol><p>Busca direcciones IP sospechosas o intentos de acceso repetidos.</p><ol start="2"><li><strong>Instalar herramientas IDS/IPS:</strong></li></ol><ul><li>Usa herramientas como <code>fail2ban</code> o <code>Snort</code> para bloquear automáticamente los intentos de acceso no autorizados.</li></ul><ol start="3"><li><p><strong>Escanear tu propio servidor con nmap:</strong></p><pre><code>sudo nmap localhost
</code></pre></li></ol><p>Identifica puertos abiertos innecesarios y ciérralos.</p><h3 id="p4-¿como-puedo-comprobar-que-proceso-esta-usando-un-puerto-especifico" tabindex="-1">P4. ¿Cómo puedo comprobar qué proceso está usando un puerto específico? <a class="header-anchor" href="#p4-¿como-puedo-comprobar-que-proceso-esta-usando-un-puerto-especifico" aria-label="Permalink to “P4. ¿Cómo puedo comprobar qué proceso está usando un puerto específico?”">​</a></h3><p><strong>R:</strong><br> Usa el comando <code>lsof</code>:</p><pre><code>sudo lsof -i :[portnumber]
</code></pre><p>Ejemplo para el puerto 80:</p><pre><code>sudo lsof -i :80
</code></pre><p><strong>Salida de ejemplo:</strong></p><pre><code>COMMAND   PID   USER   FD   TYPE DEVICE SIZE/OFF NODE NAME
apache2   1234  www    4u   IPv4  12345 0t0      TCP *:http (LISTEN)
</code></pre><h3 id="p5-¿como-permito-solo-una-direccion-ip-especifica-usando-ufw" tabindex="-1">P5. ¿Cómo permito solo una dirección IP específica usando <code>ufw</code>? <a class="header-anchor" href="#p5-¿como-permito-solo-una-direccion-ip-especifica-usando-ufw" aria-label="Permalink to “P5. ¿Cómo permito solo una dirección IP específica usando ufw?”">​</a></h3><p><strong>R:</strong><br> Ejecuta el siguiente comando:</p><pre><code>sudo ufw allow from [IP address] to any port [portnumber] proto tcp
</code></pre><p>Ejemplo: Permitir acceso SSH desde <code>192.168.1.100</code>:</p><pre><code>sudo ufw allow from 192.168.1.100 to any port 22 proto tcp
</code></pre><h3 id="p6-¿como-puedo-cambiar-el-numero-de-puerto" tabindex="-1">P6. ¿Cómo puedo cambiar el número de puerto? <a class="header-anchor" href="#p6-¿como-puedo-cambiar-el-numero-de-puerto" aria-label="Permalink to “P6. ¿Cómo puedo cambiar el número de puerto?”">​</a></h3><p><strong>R:</strong><br> Edita el archivo de configuración del servicio correspondiente.<br> Ejemplo para SSH:</p><ol><li><p>Edita el archivo de configuración:</p><pre><code>sudo nano /etc/ssh/sshd_config
</code></pre></li><li><p>Busca la directiva <code>Port</code> y establece un nuevo número de puerto:</p><pre><code>Port 2222
</code></pre></li><li><p>Reinicia el servicio SSH:</p><pre><code>sudo systemctl restart ssh
</code></pre></li><li><p>Permite el nuevo puerto a través del firewall:</p><pre><code>sudo ufw allow 2222/tcp
</code></pre></li></ol><h3 id="p7-¿puedo-permitir-varios-puertos-a-la-vez" tabindex="-1">P7. ¿Puedo permitir varios puertos a la vez? <a class="header-anchor" href="#p7-¿puedo-permitir-varios-puertos-a-la-vez" aria-label="Permalink to “P7. ¿Puedo permitir varios puertos a la vez?”">​</a></h3><p><strong>R:</strong><br> Sí, puedes permitir varios puertos usando los siguientes métodos:</p><ol><li><p>Permitiendo un rango de puertos:</p><pre><code>sudo ufw allow 1000:2000/tcp
</code></pre></li></ol><p><strong>Explicación:</strong> Permite puertos del 1000 al 2000.</p><ol start="2"><li><p>Permitiendo puertos individualmente:</p><pre><code>sudo ufw allow 22/tcp
sudo ufw allow 80/tcp
</code></pre></li></ol><p><a href="puertos.pdf">Descargar en PDF</a></p>`,153)])])}const g=o(n,[["render",i]]);export{m as __pageData,g as default};
